Ou plus simplement utiliser un useState local dans le composant, car ce formulaire est isolé.

```jsx
import { useState } from 'react';
import { toast } from 'sonner';
import api from '../services/api';

const ChangePasswordForm = () => {
  const [form, setForm] = useState({ current: '', new: '', confirm: '' });
  const [loading, setLoading] = useState(false);
  const [errors, setErrors] = useState({});

  const validate = () => {
    const newErrors = {};
    if (form.new.length < 8) newErrors.new = 'Minimum 8 caractères';
    if (form.new !== form.confirm) newErrors.confirm = 'Les mots de passe ne correspondent pas';
    setErrors(newErrors);
    return Object.keys(newErrors).length === 0;
  };

  const handleSubmit = async (e) => {
    e.preventDefault();
    if (!validate()) return;
    setLoading(true);
    try {
      await api.post('/users/change-password', {
        currentPassword: form.current,
        newPassword: form.new
      });
      toast.success('Mot de passe modifié avec succès');
      setForm({ current: '', new: '', confirm: '' });
    } catch (error) {
      if (error.response?.status === 401) {
        setErrors({ current: 'Mot de passe actuel incorrect' });
      } else {
        toast.error('Erreur lors du changement de mot de passe');
      }
    } finally {
      setLoading(false);
    }
  };

  return (
    <form onSubmit={handleSubmit} className="space-y-4">
      <div>
        <input type="password" placeholder="Mot de passe actuel" value={form.current}
          onChange={(e) => setForm({...form, current: e.target.value})} />
        {errors.current && <p className="text-red-500 text-sm">{errors.current}</p>}
      </div>
      <div>
        <input type="password" placeholder="Nouveau mot de passe" value={form.new}
          onChange={(e) => setForm({...form, new: e.target.value})} />
        {errors.new && <p className="text-red-500 text-sm">{errors.new}</p>}
      </div>
      <div>
        <input type="password" placeholder="Confirmer" value={form.confirm}
          onChange={(e) => setForm({...form, confirm: e.target.value})} />
        {errors.confirm && <p className="text-red-500 text-sm">{errors.confirm}</p>}
      </div>
      <button type="submit" disabled={loading} className="bg-indigo-600 text-white px-4 py-2 rounded">
        {loading ? 'Chargement...' : 'Changer le mot de passe'}
      </button>
    </form>
  );
};
```

```javascript
// hooks/useProfile.js
import { useQuery, useMutation, useQueryClient } from '@tanstack/react-query';
import api from '../services/api';

const fetchProfile = async () => {
  const { data } = await api.get('/users/profile');
  return data;
};

const updateProfile = async (profileData) => {
  const { data } = await api.put('/users/profile', profileData);
  return data;
};

export const useProfile = () => {
  return useQuery({
    queryKey: ['profile'],
    queryFn: fetchProfile,
    staleTime: 5 * 60 * 1000, // 5 minutes
    retry: 1,
  });
};

export const useUpdateProfile = () => {
  const queryClient = useQueryClient();

  return useMutation({
    mutationFn: updateProfile,
    onSuccess: (updatedUser) => {
      // Met à jour le cache immédiatement
      queryClient.setQueryData(['profile'], updatedUser);
      toast.success('Profil mis à jour');
    },
    onError: (error) => {
      toast.error(error.response?.data?.message || 'Erreur lors de la mise à jour');
    }
  });
};
```

La mise à jour optimiste consiste à mettre à jour immédiatement l'interface (cache) avant même que l'API ne réponde, puis à annuler en cas d'erreur.

```javascript
export const useUpdateProfileOptimistic = () => {
  const queryClient = useQueryClient();

  return useMutation({
    mutationFn: updateProfile,
    onMutate: async (newProfileData) => {
      // Annuler les requêtes en cours
      await queryClient.cancelQueries({ queryKey: ['profile'] });

      // Sauvegarder l'ancienne valeur
      const previousProfile = queryClient.getQueryData(['profile']);

      // Mettre à jour le cache immédiatement
      queryClient.setQueryData(['profile'], (old) => ({ ...old, ...newProfileData }));

      // Retourner le contexte pour rollback
      return { previousProfile };
    },
    onError: (err, newData, context) => {
      // Restaurer l'ancienne valeur en cas d'erreur
      queryClient.setQueryData(['profile'], context.previousProfile);
      toast.error('Erreur lors de la mise à jour');
    },
    onSettled: () => {
      // Revalider pour être sûr d'avoir les données fraîches
      queryClient.invalidateQueries({ queryKey: ['profile'] });
    }
  });
};
```

Avantage : l'utilisateur voit le changement instantanément, sans attendre la réponse du serveur.
